CREATE VIEW IF NOT EXISTS v_platform_profile_tag_metric_semantics AS
SELECT
  metrics.id AS metric_id,
  metrics.workspace_id,
  metrics.profile_id,
  metrics.canonical_object_key,
  metrics.channel_object_type,
  metrics.channel_object_name,
  metrics.platform,
  metrics.tag_type,
  metrics.leaf_label,
  semantics.label_path,
  metrics.metric_name,
  metrics.metric_value,
  metrics.metric_unit,
  metrics.metric_display_value,
  metrics.profile_time_window,
  metrics.sample_size,
  semantics.layer_code,
  semantics.layer_name,
  semantics.dimension_code,
  semantics.dimension_name,
  semantics.dimension_definition,
  semantics.business_strategy,
  semantics.confidence AS mapping_confidence,
  semantics.mapping_method,
  semantics.rationale AS mapping_rationale,
  metrics.platform_tag_catalog_id,
  semantics.tag_value_mapping_id,
  semantics.inherited_tag_type_mapping_id,
  metrics.source_file,
  metrics.source_row,
  metrics.source_batch_id,
  metrics.raw_json,
  metrics.updated_at AS metric_updated_at,
  semantics.updated_at AS mapping_updated_at
FROM platform_profile_tag_metrics metrics
JOIN v_pls_platform_tag_value_semantics semantics
  ON semantics.platform_tag_catalog_id = metrics.platform_tag_catalog_id
WHERE metrics.status = 'active';

INSERT OR IGNORE INTO database_field_comments (
  id,
  table_name,
  field_name,
  zh_name,
  zh_description,
  business_meaning,
  example_value,
  source_ref,
  status,
  created_at,
  updated_at
)
